const claimRequest = require('claimRequest');
const getRequestPath = require('getRequestPath');
const getRequestMethod = require('getRequestMethod');
const getRequestBody = require('getRequestBody');
const JSON = require('JSON');
const runContainer = require('runContainer');
const returnResponse = require('returnResponse');
const setResponseStatus = require('setResponseStatus');
const logToConsole = require('logToConsole');

const path = getRequestPath();
const method = getRequestMethod();

if (method !== 'POST' || path !== '/stripe') { return; }

claimRequest();

const bodyString = getRequestBody();
if (!bodyString) { setResponseStatus(400); returnResponse(); return; }

const body = JSON.parse(bodyString);
if (!body || body.type !== 'checkout.session.completed') {
  logToConsole('Stripe Webhook: evento ignorado');
  setResponseStatus(200);
  returnResponse();
  return;
}

const session = body.data && body.data.object;
if (!session) { setResponseStatus(400); returnResponse(); return; }

// Extrair dados do cliente para melhorar EMQ (Event Match Quality) do Meta
const customerDetails = session.customer_details || {};
const fullName = (customerDetails.name || '').trim();
const spaceIndex = fullName.indexOf(' ');
const firstName = spaceIndex > -1 ? fullName.substring(0, spaceIndex) : fullName;
const lastName = spaceIndex > -1 ? fullName.substring(spaceIndex + 1) : '';

const userData = {};
if (customerDetails.email) { userData.em = customerDetails.email; }
if (customerDetails.phone) { userData.ph = customerDetails.phone; }
if (firstName) { userData.fn = firstName; }
if (lastName) { userData.ln = lastName; }
if (session.customer) { userData.external_id = session.customer; }

const eventData = {
  event_name: 'purchase',
  currency: session.currency ? session.currency.toUpperCase() : 'BRL',
  value: session.amount_total ? session.amount_total / 100 : 0,
  transaction_id: session.id,
  client_id: session.client_reference_id || session.customer || '',
  negocio: (session.metadata && session.metadata.negocio) ? session.metadata.negocio : 'app_online',
  user_data: userData
};

logToConsole('Stripe Webhook: purchase recebido', eventData);

runContainer(eventData, () => {
  setResponseStatus(200);
  returnResponse();
});


